# ══════════════════════════════════════════════════════════════
#  LOAD DATA — Optional Excel at startup
# ══════════════════════════════════════════════════════════════
def load_data():
    if os.path.exists(EXCEL_FILE):
        df = pd.read_excel(EXCEL_FILE)
        df.columns = COLS
        df = df.dropna(subset=["Mixture"]).reset_index(drop=True)
        for col in COLS[3:]:
            df[col] = pd.to_numeric(df[col], errors="coerce")
        return df
    return pd.DataFrame(columns=COLS)

PALETTE     = ["#2196F3", "#FF5722", "#4CAF50", "#9C27B0",
               "#FF9800", "#009688", "#F44336", "#3F51B5"]

# ── Helper: rebuild df and derived lists from Store data ──────
def df_from_store(store_data):
    """Reconstruct df, water_types, mix_names from dcc.Store payload."""
    if not store_data:
        return pd.DataFrame(columns=COLS), [], []
    df = pd.DataFrame(store_data)
    if "Mixture" not in df.columns:
        return pd.DataFrame(columns=COLS), [], []
    df = df.dropna(subset=["Mixture"]).reset_index(drop=True)
    for col in COLS[3:]:
        if col in df.columns:
            df[col] = pd.to_numeric(df[col], errors="coerce")
    wt = list(dict.fromkeys(df["Water"].dropna()))
    mn = list(dict.fromkeys(df["Mixture"].dropna()))
    return df, wt, mn

def get_df_wt(df_all, water_type):
    return df_all[df_all["Water"] == water_type].reset_index(drop=True)

