# ══════════════════════════════════════════════════════════════
#  QC FUNCTIONS — Code-aware
# ══════════════════════════════════════════════════════════════
def qc_row(c7, c28, code="ECP 203"):
    ci = BUILDING_CODES[code]
    if pd.isna(c28) or pd.isna(c7) or c28 == 0:
        return "—", "—", "—"
    ok28  = "✅ Pass" if c28 >= ci["min_28"] else "❌ Fail"
    if ok28 == "❌ Fail":
        return ok28, "—", "—"
    ratio = c7 / c28
    ok7   = "✅ Pass" if ci["adv_lo"] <= ratio <= ci["adv_hi"] else "⚠️ Check"
    return ok28, ok7, f"{ratio*100:.1f}%"

def build_qc_df(df, code="ECP 203"):
    ci  = BUILDING_CODES[code]
    col28 = ci["min_label"]
    col7  = f"7d Ratio ({ci['adv_label']})"
    rows = []
    for _, r in df.iterrows():
        ok28, ok7, ratio = qc_row(r["Comp7"], r["Comp28"], code)
        rows.append({
            "No.": r["No"], "Mixture": r["Mixture"], "Water": r["Water"],
            "Comp 7d": r["Comp7"], "Comp 28d": r["Comp28"],
            "7d/28d": ratio, col28: ok28, col7: ok7,
        })
    return pd.DataFrame(rows)

def auto_summary(code="ECP 203", df_all=None, water_types=None, mix_names=None):
    ci = BUILDING_CODES[code]
    if df_all is None:
        df_all = load_data()
    if water_types is None:
        water_types = list(df_all["Water"].dropna().unique())
    if mix_names is None:
        mix_names = list(dict.fromkeys(df_all["Mixture"].dropna()))
    lines = []
    for wt in water_types:
        dft = df_all[df_all["Water"]==wt]
        if dft.empty or dft["Comp28"].dropna().empty:
            continue
        best = dft.loc[dft["Comp28"].idxmax()]
        lines.append(f"🏆  Best ({wt}): {best['Mixture']} → {best['Comp28']} kg/cm²")
    if len(water_types) >= 2:
        t1, t2 = water_types[0], water_types[1]
        df1 = df_all[df_all["Water"]==t1]
        df2 = df_all[df_all["Water"]==t2]
        imps = []
        for m in mix_names:
            v1 = df1.loc[df1["Mixture"]==m, "Comp28"].values
            v2 = df2.loc[df2["Mixture"]==m, "Comp28"].values
            if len(v1) and len(v2) and v1[0] > 0:
                imps.append((v2[0]-v1[0])/v1[0]*100)
        if imps:
            lines.append(f"📈  Avg improvement {t2} vs {t1}: +{sum(imps)/len(imps):.1f}%")
    total  = len(df_all.dropna(subset=["Comp28"]))
    passed = int((df_all["Comp28"] >= ci["min_28"]).sum())
    lines.append(f"✅  {code} compliance (28d ≥ {ci['min_28']:.0f}): {passed}/{total} passed")
    return lines

