def wrap_label(name):
    for sep in [" + ", "% ", " & "]:
        idx = name.find(sep)
        if idx != -1 and idx > 3:
            cut = idx + len(sep)
            return name[:cut].rstrip() + "<br>" + name[cut:].lstrip()
    if len(name) > 18:
        mid = len(name) // 2
        sp  = name.rfind(" ", 0, mid + 6)
        if sp > 0:
            return name[:sp] + "<br>" + name[sp+1:]
    return name

