#  PDF CALLBACK
# ══════════════════════════════════════════════════════════════
@app.callback(Output("download-pdf", "data"),
              Input("btn-pdf", "n_clicks"),
              State("code-dropdown", "value"),
              prevent_initial_call=True)
def generate_pdf(_, code):
    code       = code or "ECP 203"
    ci         = BUILDING_CODES[code]
    print_time = datetime.now()
    print_date = print_time.strftime("%d %B %Y")
    print_dt   = print_time.strftime("%d %B %Y  at  %H:%M")
    fname      = f"QC_Report_{code.replace(' ','_')}_{print_time.strftime('%Y%m%d_%H%M')}.pdf"

    buf = io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            leftMargin=2*cm, rightMargin=2*cm,
                            topMargin=2*cm, bottomMargin=2*cm)
    W   = A4[0] - 4*cm

    title_s   = ParagraphStyle("ts",  fontSize=16, fontName="Helvetica-Bold",
                                textColor=colors.HexColor("#1565C0"),
                                alignment=TA_CENTER, spaceAfter=6)
    sub_s     = ParagraphStyle("ss",  fontSize=11, fontName="Helvetica",
                                textColor=colors.HexColor("#444444"),
                                alignment=TA_CENTER, spaceAfter=4)
    h2_s      = ParagraphStyle("h2",  fontSize=13, fontName="Helvetica-Bold",
                                textColor=colors.HexColor("#1565C0"),
                                spaceBefore=14, spaceAfter=6)
    normal_s  = ParagraphStyle("ns",  fontSize=9,  fontName="Helvetica",
                                leading=14, spaceAfter=4)
    small_s   = ParagraphStyle("sms", fontSize=8,  fontName="Helvetica",
                                leading=12, alignment=TA_CENTER)
    caption_s = ParagraphStyle("cs",  fontSize=8,  fontName="Helvetica-Oblique",
                                textColor=colors.grey, alignment=TA_CENTER)
    cell_s    = ParagraphStyle("cel", fontSize=8,  fontName="Helvetica",
                                leading=11, alignment=TA_CENTER, wordWrap="CJK")

    PASS_BG   = colors.HexColor("#C8E6C9")
    WARN_BG   = colors.HexColor("#FFF9C4")
    HEAD_COLOR= colors.HexColor("#1565C0")

    def section(title):
        return [Paragraph(title, h2_s),
                HRFlowable(width=W, thickness=1, color=HEAD_COLOR, spaceAfter=8)]

    def pass_badge(text):
        return Paragraph(f'<font color="#1B5E20"><b>{text}</b></font>', small_s)

    def warn_badge(text):
        return Paragraph(f'<font color="#E65100"><b>{text}</b></font>', small_s)

    def cell_p(text):
        return Paragraph(str(text), cell_s)

    def base_tbl(data, col_widths, extra_styles=None):
        t = Table(data, colWidths=col_widths, repeatRows=1)
        cmds = [
            ("BACKGROUND",     (0,0), (-1,0), HEAD_COLOR),
            ("TEXTCOLOR",      (0,0), (-1,0), colors.white),
            ("FONTNAME",       (0,0), (-1,0), "Helvetica-Bold"),
            ("FONTSIZE",       (0,0), (-1,-1), 8),
            ("ALIGN",          (0,0), (-1,-1), "CENTER"),
            ("VALIGN",         (0,0), (-1,-1), "MIDDLE"),
            ("GRID",           (0,0), (-1,-1), 0.4, colors.HexColor("#BBBBBB")),
            ("ROWBACKGROUNDS", (0,1), (-1,-1),
             [colors.HexColor("#F5F9FF"), colors.white]),
            ("TOPPADDING",     (0,0), (-1,-1), 5),
            ("BOTTOMPADDING",  (0,0), (-1,-1), 5),
            ("LEFTPADDING",    (0,0), (-1,-1), 4),
            ("RIGHTPADDING",   (0,0), (-1,-1), 4),
        ]
        if extra_styles:
            cmds += extra_styles
        t.setStyle(TableStyle(cmds))
        return t

    story = []
    from reportlab.platypus import Image as RLImage

    logo_img      = io.BytesIO(base64.b64decode(LOGO_RIGHT_B64))
    logo_rl       = RLImage(logo_img, width=2.8*cm, height=2.4*cm)
    logo_left_img = io.BytesIO(base64.b64decode(LOGO_LEFT_B64))
    logo_left_rl  = RLImage(logo_left_img, width=2.8*cm, height=2.4*cm)

    logo_tbl = Table(
        [[logo_left_rl,
          Paragraph(f"<b>{PROJECT_INFO['university']}</b><br/>"
                    f"{PROJECT_INFO['faculty']}<br/>"
                    f"{PROJECT_INFO['department']}",
                    ParagraphStyle("ct", fontSize=12, fontName="Helvetica-Bold",
                                   textColor=HEAD_COLOR, alignment=TA_CENTER,
                                   leading=18)),
          logo_rl]],
        colWidths=[3*cm, W-6*cm, 3*cm])
    logo_tbl.setStyle(TableStyle([
        ("ALIGN",  (0,0), (-1,-1), "CENTER"),
        ("VALIGN", (0,0), (-1,-1), "MIDDLE"),
    ]))

    story += [
        Spacer(1, 0.8*cm),
        logo_tbl,
        Spacer(1, 0.6*cm),
        HRFlowable(width=W, thickness=2, color=HEAD_COLOR),
        Spacer(1, 0.4*cm),
        Paragraph("DIGITAL QUALITY CONTROL REPORT", title_s),
        Paragraph(PROJECT_INFO["title"].replace("\n","<br/>"), sub_s),
        Spacer(1, 0.4*cm),
        HRFlowable(width=W, thickness=2, color=HEAD_COLOR),
        Spacer(1, 0.6*cm),
    ]



    meta_data = [
        ["Academic Year",  PROJECT_INFO["year"]],
        ["Active Standard", ci["name"]],
        ["Min. Strength",   ci["min_label"]],
        ["Advisory Check",  ci["adv_label"]],
        ["Report Date",     print_date],
        ["Printed at",      print_dt],
    ]
    meta_tbl = Table(meta_data, colWidths=[3.5*cm, W-3.5*cm])
    meta_tbl.setStyle(TableStyle([
        ("FONTNAME",       (0,0),(0,-1), "Helvetica-Bold"),
        ("FONTSIZE",       (0,0),(-1,-1), 9),
        ("TEXTCOLOR",      (0,0),(0,-1), HEAD_COLOR),
        ("ALIGN",          (0,0),(-1,-1), "LEFT"),
        ("VALIGN",         (0,0),(-1,-1), "MIDDLE"),
        ("TOPPADDING",     (0,0),(-1,-1), 5),
        ("BOTTOMPADDING",  (0,0),(-1,-1), 5),
        ("LEFTPADDING",    (0,0),(-1,-1), 8),
        ("ROWBACKGROUNDS", (0,0),(-1,-1),
         [colors.HexColor("#F0F7FF"), colors.white]),
        ("GRID",           (0,0),(-1,-1), 0.4, colors.HexColor("#C5CAE9")),
    ]))
    story += [meta_tbl, PageBreak()]

    # ── Section 1: QC Compliance ──────────────────────────────
    story += section(f"1.  {code} Compliance Check")
    story.append(Paragraph(
        f"All mixtures evaluated against {ci['name']}. "
        f"Pass criteria: (a) {ci['min_label']}  "
        f"(b) {ci['adv_label']}.", normal_s))
    story.append(Spacer(1, 0.25*cm))

    qc_df = build_qc_df(df_all, code)
    col28 = ci["min_label"]
    col7  = f"7d Ratio ({ci['adv_label']})"

    legend_tbl = Table(
        [[pass_badge("PASS"), "  Meets requirement",
          warn_badge("! CHECK"), "  Outside target range"]],
        colWidths=[1.8*cm, 4*cm, 2*cm, 4*cm])
    legend_tbl.setStyle(TableStyle([
        ("ALIGN",  (0,0),(-1,-1), "LEFT"),
        ("VALIGN", (0,0),(-1,-1), "MIDDLE"),
        ("FONTSIZE",(0,0),(-1,-1), 8),
        ("BACKGROUND",(0,0),(0,0), PASS_BG),
        ("BACKGROUND",(2,0),(2,0), WARN_BG),
        ("GRID",   (0,0),(-1,-1), 0, colors.white),
        ("TOPPADDING",(0,0),(-1,-1), 3),
        ("BOTTOMPADDING",(0,0),(-1,-1), 3),
    ]))
    story += [legend_tbl, Spacer(1, 0.2*cm)]

    qc_hdr  = ["No.", "Mixture", "Water",
               "Comp\n7d", "Comp\n28d", "7d/28d",
               "28d\nCheck", "7d\nRatio"]
    qc_data = [qc_hdr]
    pass28_rows, warn28_rows, pass7_rows, warn7_rows = [], [], [], []

    for i, (_, r) in enumerate(qc_df.iterrows(), start=1):
        v28 = r[col28]
        v7  = r[col7]
        b28 = pass_badge("PASS") if "Pass" in str(v28) else warn_badge("FAIL")
        b7  = pass_badge("PASS") if "Pass" in str(v7)  else warn_badge("CHECK")
        if "Pass" in str(v28): pass28_rows.append(i)
        else:                  warn28_rows.append(i)
        if "Pass" in str(v7):  pass7_rows.append(i)
        else:                  warn7_rows.append(i)
        qc_data.append([r["No."], cell_p(r["Mixture"]), r["Water"],
                        r["Comp 7d"], r["Comp 28d"], r["7d/28d"], b28, b7])

    cws_qc = [1.0*cm, 5.0*cm, 2.2*cm, 1.6*cm, 1.7*cm, 1.5*cm, 1.8*cm, 1.9*cm]
    extra  = ([("BACKGROUND",(6,ri),(6,ri), PASS_BG) for ri in pass28_rows] +
              [("BACKGROUND",(6,ri),(6,ri), WARN_BG) for ri in warn28_rows] +
              [("BACKGROUND",(7,ri),(7,ri), PASS_BG) for ri in pass7_rows]  +
              [("BACKGROUND",(7,ri),(7,ri), WARN_BG) for ri in warn7_rows])
    story.append(base_tbl(qc_data, cws_qc, extra_styles=extra))
    story.append(Spacer(1, 0.3*cm))

    total  = len(qc_df.dropna(subset=["Comp 28d"]))
    passed = qc_df[col28].str.contains("Pass").sum()
    story.append(Paragraph(
        f"<b>Result:</b>  {passed} out of {total} mixtures passed "
        f"the {code} 28-day requirement.", normal_s))
    story.append(PageBreak())

    # ── Section 2: Compressive Strength ───────────────────────
    story += section("2.  Compressive Strength Results")
    comp_hdr  = ["Mixture", "Water", "7-day\n(kg/cm2)",
                 "28-day\n(kg/cm2)", "56-day\n(kg/cm2)"]
    comp_data = [comp_hdr]
    for _, r in df_all.dropna(subset=["Comp28"]).iterrows():
        comp_data.append([cell_p(r["Mixture"]), r["Water"],
                          r["Comp7"], r["Comp28"], r["Comp56"]])
    story.append(base_tbl(comp_data,
                          [5.0*cm, 2.2*cm, 2.6*cm, 2.6*cm, 2.6*cm]))
    story.append(PageBreak())

    # ── Section 3: Tensile & Flexure ──────────────────────────
    story += section("3.  Tensile & Flexure Strength @ 28 Days")
    tf_hdr  = ["Mixture", "Water", "Tensile\n(kg/cm2)", "Flexure\n(kg/cm2)"]
    tf_data = [tf_hdr]
    for _, r in df_all.dropna(subset=["Tensile28"]).iterrows():
        tf_data.append([cell_p(r["Mixture"]), r["Water"],
                        r["Tensile28"], r["Flexure28"]])
    story.append(base_tbl(tf_data, [5.0*cm, 2.2*cm, 3.6*cm, 3.6*cm]))
    story.append(Spacer(1, 0.4*cm))

    # ── Section 4: Water Type Comparison ──────────────────────
    if len(WATER_TYPES) >= 2:
        t1, t2 = WATER_TYPES[0], WATER_TYPES[1]
        df1, df2 = get_df(t1), get_df(t2)
        story += section(f"4.  Water Type Comparison: {t2} vs {t1}  (Comp. @ 28d)")
        imp_hdr  = ["Mixture",
                    f"{t1}\n(kg/cm2)",
                    f"{t2}\n(kg/cm2)",
                    "Improvement"]
        imp_data = [imp_hdr]
        imp_idx  = []
        for i, (_, ro) in enumerate(df1.iterrows(), start=1):
            rm = df2[df2["Mixture"] == ro["Mixture"]]
            if not rm.empty:
                rm  = rm.iloc[0]
                imp = round((rm["Comp28"]-ro["Comp28"])/ro["Comp28"]*100, 1)
                imp_data.append([cell_p(ro["Mixture"]),
                                  ro["Comp28"], rm["Comp28"],
                                  Paragraph(
                                      f'<font color="#1B5E20"><b>+{imp}%</b></font>',
                                      small_s)])
                imp_idx.append(len(imp_data)-1)
        imp_extra = [("BACKGROUND",(3,ri),(3,ri), PASS_BG) for ri in imp_idx]
        story.append(base_tbl(imp_data,
                              [5.0*cm, 2.8*cm, 2.8*cm, 2.8*cm],
                              extra_styles=imp_extra))
        story.append(PageBreak())

    # ── Section 5: Compressive Strength Charts ────────────────
    story += section("5.  Compressive Strength Charts")
    for col, title_c, add_min in [
        ("Comp7",  "Compressive Strength @ 7 Days",  False),
        ("Comp28", "Compressive Strength @ 28 Days",  True),
        ("Comp56", "Compressive Strength @ 56 Days",  False),
    ]:
        png_bytes = make_bar_png(col, title_c, "kg/cm²",
                                  code_min=ci["min_28"] if add_min else None)
        story.append(RLImage(io.BytesIO(png_bytes), width=W, height=W * 0.42))
        story.append(Spacer(1, 0.25 * cm))
    story.append(PageBreak())

    # ── Section 6: Tensile & Flexure Charts ───────────────────
    story += section("6.  Tensile & Flexure Strength Charts")
    for col, title_c in [
        ("Tensile28", "Tensile Strength @ 28 Days"),
        ("Flexure28", "Flexure Strength @ 28 Days"),
    ]:
        png_bytes = make_bar_png(col, title_c, "kg/cm²")
        story.append(RLImage(io.BytesIO(png_bytes), width=W, height=W * 0.42))
        story.append(Spacer(1, 0.25 * cm))

    # ── Section 7: Improvement Charts (only if 2+ water types) ─
    if len(WATER_TYPES) >= 2:
        story.append(PageBreak())
        t1_imp, t2_imp = WATER_TYPES[0], WATER_TYPES[1]
        story += section(f"7.  Strength Improvement — {t2_imp} vs {t1_imp}")
        png_imp = make_improvement_png()
        if png_imp:
            story.append(RLImage(io.BytesIO(png_imp), width=W, height=W * 0.48))
            story.append(Spacer(1, 0.3 * cm))

    story.append(PageBreak())

    # ── Section 8: Conclusions ────────────────────────────────
    story += section("8.  Conclusions & Recommendations")
    for line in auto_summary(code):
        clean = line.replace("✅","").replace("🏆","").replace("📈","").replace("🔬","")
        story.append(Paragraph(f"•  {clean.strip()}", normal_s))

    story += [
        Spacer(1, 1*cm),
        HRFlowable(width=W, thickness=1, color=colors.HexColor("#CCCCCC")),
        Spacer(1, 0.3*cm),
        Paragraph(f"This report was generated automatically by the "
                  f"Green Concrete Digital QC System  |  Standard: {ci['name']}",
                  caption_s),
        Paragraph(f"Printed on:  {print_dt}", caption_s),
    ]

    doc.build(story)
    buf.seek(0)
    return dcc.send_bytes(buf.read(), fname)


