# ══════════════════════════════════════════════════════════════
#  INPUT DATA CALLBACKS
# ══════════════════════════════════════════════════════════════
@app.callback(
    Output("data-store", "data"),
    Output("apply-status", "children"),
    Input("apply-btn", "n_clicks"),
    State("input-table", "data"),
    prevent_initial_call=True,
)
def apply_table(n, table_data):
    if not table_data:
        return [], "⚠️ No data to apply."
    df = pd.DataFrame(table_data)
    df = df[df["Mixture"].astype(str).str.strip() != ""]
    df = df[df["Mixture"].notna()]
    for col in COLS[3:]:
        if col in df.columns:
            df[col] = pd.to_numeric(df[col], errors="coerce")
    return df.to_dict("records"), f"✅ Applied — {len(df)} rows loaded."

@app.callback(
    Output("input-table", "data"),
    Input("add-row-btn", "n_clicks"),
    State("input-table", "data"),
    prevent_initial_call=True,
)
def add_row(n, rows):
    if rows is None:
        rows = []
    rows.append({c: "" for c in COLS})
    return rows

@app.callback(
    Output("data-store", "data", allow_duplicate=True),
    Output("input-table", "data", allow_duplicate=True),
    Input("upload-excel", "contents"),
    State("upload-excel", "filename"),
    prevent_initial_call=True,
)
def import_excel(contents, filename):
    if contents is None:
        return dash.no_update, dash.no_update
    try:
        content_type, content_string = contents.split(",")
        decoded = base64.b64decode(content_string)
        df = pd.read_excel(io.BytesIO(decoded))
        df.columns = COLS[:len(df.columns)]
        df = df.dropna(subset=["Mixture"]).reset_index(drop=True)
        for col in COLS[3:]:
            if col in df.columns:
                df[col] = pd.to_numeric(df[col], errors="coerce")
        records = df.to_dict("records")
        return records, records
    except Exception as e:
        return dash.no_update, dash.no_update

# ══════════════════════════════════════════════════════════════
#  IMPROVEMENT CHART CALLBACKS (with reference dropdown)
# ══════════════════════════════════════════════════════════════
def _make_imp_fig_comp(ref, code, store_data):
    df_s, water_types, mix_names = df_from_store(store_data)
    if not ref or len(water_types) < 2:
        return go.Figure()
    ci   = BUILDING_CODES.get(code or "ECP 203", BUILDING_CODES["ECP 203"])
    df_ref  = df_s[df_s["Water"] == ref]
    others  = [wt for wt in water_types if wt != ref]
    fig     = go.Figure()
    colors_ = [("#42A5F5","7d"), ("#1565C0","28d"), ("#0D47A1","56d")]
    for ot in others:
        df_ot = df_s[df_s["Water"] == ot]
        for col, color, day in [("Comp7","#42A5F5","7d"),
                                  ("Comp28","#1565C0","28d"),
                                  ("Comp56","#0D47A1","56d")]:
            vals = []
            for m in mix_names:
                v1 = df_ref.loc[df_ref["Mixture"]==m, col].values
                v2 = df_ot.loc[df_ot["Mixture"]==m, col].values
                vals.append(round((v2[0]-v1[0])/v1[0]*100,1)
                            if len(v1) and len(v2) and v1[0] else 0)
            fig.add_bar(name=f"{day} — {ot} vs {ref}",
                        x=[wrap_label(m) for m in mix_names],
                        y=vals, marker_color=color, opacity=0.87)
    fig.update_layout(
        title=f"Compressive Improvement % — vs reference: {ref}",
        barmode="group", yaxis_title="Improvement %",
        plot_bgcolor="white", paper_bgcolor="white",
        legend=dict(orientation="h", y=1.12), height=520,
        margin=dict(t=60, b=230),
        xaxis=dict(tickangle=0, tickfont=dict(size=8), automargin=True))
    return fig

@app.callback(
    Output("imp-comp-graph", "figure"),
    Input("imp-comp-ref", "value"),
    Input("code-dropdown", "value"),
    Input("data-store", "data"),
    prevent_initial_call=False,
)
def update_imp_comp(ref, code, store_data):
    return _make_imp_fig_comp(ref, code, store_data)

